package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*

class SharedFlowLintTest : TestBase() {
    @Test
    fun testToListWarning() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 1)
        sharedFlow.emit(1)
        // This should call SharedFlow.toList from Lint.kt and we'd hope for a warning during compilation
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            val list = sharedFlow.toList() 
            assertEquals(listOf(1), list) // This will never be reached because it never completes
        }
        job.cancel()
    }
}
